1	\chapter{The Abel--Jacobi map}
2	\label{chap:AbelJacobi}
3	
4	Let $C$ be a smooth proper curve over $k$ as in Chapter~\ref{chap:Genus}, and let $\Jac(C)$ be its Jacobian (Definition~\ref{def:Jacobian}). The constructions of this chapter consume only the Albanese universal property of $\Jac(C)$, as packaged by Definition~\ref{def:IsAlbanese} and provided uniformly in the marked point by Theorem~\ref{thm:nonempty_jacobianWitness}. The Lean formalisation closes every block in this chapter by a single projection from the Albanese structure $\mathrm{IsAlbanese}\,C\,P\,\Jac(C)$; the corresponding classical line-bundle / Pic-scheme description is recorded as a remark for each block.
5	
6	\section{Definition}
7	
8	\begin{definition}\leanok
9	[Abel--Jacobi map]
10	  \label{def:ofCurve}
11	  \lean{AlgebraicGeometry.Jacobian.ofCurve}
12	  \uses{def:Jacobian, def:IsAlbanese, thm:nonempty_jacobianWitness}
13	  Let $P \colon \Spec k \to C$ be a $k$-rational point of $C$, equivalently a morphism $P \colon \mathbf 1 \to C$ in the category of $k$-schemes over $\Spec k$. By Theorem~\ref{thm:nonempty_jacobianWitness} the Jacobian $\Jac(C)$ of Definition~\ref{def:Jacobian} carries, for each such marked point $P$, an Albanese structure $\mathrm{IsAlbanese}\,C\,P\,\Jac(C)$ in the sense of Definition~\ref{def:IsAlbanese}. The \emph{Abel--Jacobi map at $P$} is the universal pointed morphism $\iota_P$ supplied by that Albanese structure:
14	  \[
15	    \alpha_P \;:=\; \iota_P \;\colon\; C \;\longrightarrow\; \Jac(C).
16	  \]
17	  Equivalently, $\alpha_P$ is the projection of the universal-pointed-morphism field of the Albanese predicate $\mathrm{IsAlbanese}\,C\,P\,\Jac(C)$, evaluated at the marked point $P$.
18	\end{definition}
19	
20	\begin{remark}
21	[Classical description (Pic-scheme route)]
22	  \label{rem:ofCurve_classical}
23	  \uses{def:ofCurve, thm:nonempty_jacobianWitness}
24	  Classically (cf.\ Hartshorne~III.4 and FGA Explained, Chapter~9), the Abel--Jacobi map at $P$ admits the line-bundle description
25	  \[
26	    \alpha_P \colon C \;\longrightarrow\; \Pic^0_{C/k},\qquad Q \;\longmapsto\; [\mathcal O_C(Q - P)].
27	  \]
28	  Functorially, it is the morphism in the category of $k$-schemes induced by the line bundle $\mathcal O_{C \times C}(\Delta - p_1^* P)$ on $C \times C$ via the universal property of $\Pic^0_{C/k}$ as the moduli space of degree-$0$ line bundles on $C$. The Lean formalisation does not follow this route: the Pic-scheme representability machinery (Route~A of the proof of Theorem~\ref{thm:nonempty_jacobianWitness}, in particular sub-step~A.2) is not currently available in Mathlib. See Layer~I of Chapter~\ref{chap:Jacobian} for the formalisation route actually taken.
29	\end{remark}
30	
31	\section{Pointed property}
32	
33	\begin{lemma}\leanok
34	[$\alpha_P$ sends $P$ to $0$]
35	  \label{lem:comp_ofCurve}
36	  \lean{AlgebraicGeometry.Jacobian.comp_ofCurve}
37	  \uses{def:ofCurve, def:IsAlbanese}
38	  $P \;\circ\; \alpha_P \;=\; \eta[\Jac(C)]$, where $\eta[\Jac(C)]$ is the identity element of the group scheme $\Jac(C)$.
39	\end{lemma}
40	
41	\begin{proof}
42	  \uses{def:ofCurve, def:IsAlbanese, thm:nonempty_jacobianWitness}
43	  \leanok
44	  The Lean closure is the field projection from the Albanese structure $\mathrm{IsAlbanese}\,C\,P\,\Jac(C)$ supplied by Theorem~\ref{thm:nonempty_jacobianWitness}. By Definition~\ref{def:IsAlbanese}, this predicate carries among its data the assertion $P \circ \iota_P = \eta_{\Jac(C)}$ that the universal pointed morphism sends the marked point to the identity of the target group scheme. Since $\alpha_P := \iota_P$ by Definition~\ref{def:ofCurve}, the claim is precisely the pointed-property field of that Albanese structure.
45	\end{proof}
46	
47	\begin{remark}
48	[Classical description]
49	  \label{rem:comp_ofCurve_classical}
50	  \uses{def:ofCurve, lem:comp_ofCurve, rem:ofCurve_classical}
51	  Under the classical Pic-scheme description of Remark~\ref{rem:ofCurve_classical}, the same equality reads at the level of $k$-points as
52	  \[
53	    \alpha_P(P) \;=\; [\mathcal O_C(P - P)] \;=\; [\mathcal O_C] \;=\; 0 \in \Pic^0_{C/k}(k),
54	  \]
55	  and globally as the statement that restricting the universal line bundle $\mathcal O_{C \times C}(\Delta - p_1^* P)$ along the section $(P, \mathrm{id}) \colon C \to C \times C$ gives the trivial line bundle on $C$, hence the zero point of $\Pic^0_{C/k}$. This classical content is not used in the Lean formalisation.
56	\end{remark}
57	
58	\section{Universal (Albanese) property}
59	
60	\begin{theorem}\leanok
61	[Albanese property of the Jacobian]
62	  \label{thm:exists_unique_ofCurve_comp}
63	  \lean{AlgebraicGeometry.Jacobian.exists_unique_ofCurve_comp}
64	  \uses{def:ofCurve, lem:comp_ofCurve, def:IsAlbanese}
65	  Let $A$ be an abelian variety over $k$ --- i.e.\ a smooth proper geometrically irreducible group scheme over $k$. For every pointed morphism $f \colon C \to A$ with $f \circ P = \eta[A]$, there exists a unique group-scheme morphism $g \colon \Jac(C) \to A$ such that $f = \alpha_P \circ g$.
66	  \[
67	  \begin{array}{ccc}
68	    C & \stackrel{f}{\longrightarrow} & A \\
69	    {\scriptstyle\alpha_P} \downarrow & \nearrow {\scriptstyle\exists ! g} & \\
70	    \Jac(C) & &
71	  \end{array}
72	  \]
73	\end{theorem}
74	
75	\begin{proof}
76	  \uses{def:IsAlbanese, thm:nonempty_jacobianWitness, def:ofCurve, lem:comp_ofCurve}
77	  \leanok
78	  The argument has two stages: the Lean closure (a direct projection from an Albanese witness) and the classical description (a Pic-scheme / rigidity argument that the Lean side does not replay).
79	
80	  \emph{Lean closure.} By Theorem~\ref{thm:nonempty_jacobianWitness}, the Jacobian $\Jac(C)$ is, uniformly in the marked point $P$, the underlying scheme of an Albanese witness for the pointed curve $(C, P)$: it carries an Albanese structure $\mathrm{IsAlbanese}\,C\,P\,\Jac(C)$ in the sense of Definition~\ref{def:IsAlbanese}, whose universal pointed morphism is the Abel--Jacobi map $\alpha_P$ of Definition~\ref{def:ofCurve} (with $\alpha_P \circ P = \eta_{\Jac(C)}$ being Lemma~\ref{lem:comp_ofCurve}). The universal-property data carried by this Albanese structure is, by Definition~\ref{def:IsAlbanese}, exactly the existence-and-uniqueness assertion of the theorem: for every $f \colon C \to A$ with $f \circ P = \eta_A$, there is a unique $g \colon \Jac(C) \to A$ with $f = \alpha_P \circ g$. The Lean side closes the goal by projecting this universal-property field of the Albanese witness $\mathrm{IsAlbanese}\,C\,P\,\Jac(C)$, applied to the data $(f, hf)$.
81	
82	  \emph{Classical description.} The classical proof of the same statement proceeds in two parts. In positive genus ($g(C) > 0$), the existence and uniqueness of the factorisation come from the Pic-scheme representability theorem together with the Stein factorisation of the Abel--Jacobi morphism: see Theorem~\ref{thm:nonempty_jacobianWitness}, Route~A (sub-steps A.1--A.4) for the line-bundle / universal-property route via $\Pic^0_{C/k}$, and Route~B (sub-steps B.1--B.3) for the symmetric-power / Stein-factorisation route. In genus $0$, the same statement reduces to the rigidity theorem for $C \to A$ established \emph{directly over $k$} --- the named declaration \cref{thm:rigidity_over_kbar} of \cref{chap:RigidityKbar}, whose signature is $k$-agnostic per the iter-127 over-k commitment (\texttt{analogies/cotangent-vanishing-pile-over-k.md}) and which is built out of the shared cotangent-vanishing pile pieces (i)+(ii)+(iii) over an arbitrary base field with no algebraic-closure, perfect-base, or Galois-descent hypothesis. See Theorem~\ref{thm:nonempty_jacobianWitness}, sub-cases C.1--C.3, in particular the seven-step expansion C.2.a--C.2.g, where sub-step C.2.f (Galois descent of morphism equality back to $k$) is \textbf{DROPPED} under the iter-127 commitment: no base-change-and-descent step appears anywhere in the M2 critical path. The protected signature of Theorem~\ref{thm:nonempty_jacobianWitness} does \emph{not} assume $C(k) \neq \emptyset$, so the genus-$0$ argument branches on whether a $k$-rational point exists. When $C(k) \neq \emptyset$, the supplied $P \in C(k)$ feeds the pointing hypothesis of \cref{thm:rigidity_over_kbar} directly --- no $C \cong \mathbb P^1_k$ identification is required, sidestepping the Brauer--Severi obstruction (Brauer--Severi conics over $\mathbb Q$ are the standard counterexample to an unconditional $k$-side identification). When $C(k) = \emptyset$, the $\mathtt{isAlbaneseFor}$ field of the genus-$0$ witness (\cref{def:genusZeroWitness}) is vacuously true at the Lean type level: the universal quantifier $\forall\, (P \colon \mathbf{1} \to C)$ ranges over the empty type. None of this classical content is replayed in the Lean formalisation: it is bundled into the deferred existence hypothesis Theorem~\ref{thm:nonempty_jacobianWitness}, whose proof is the project's single explicit foundational gap.
83	\end{proof}
84	
85	\section{Implementation route via the Albanese framework}
86	
87	The three results above are formalised through the Albanese framework of Chapter~\ref{chap:Jacobian}. In the absence of Mathlib's Pic-scheme machinery, the Jacobian is defined (Layer~I) as the underlying scheme of an Albanese witness uniform in the marked point (Theorem~\ref{thm:nonempty_jacobianWitness}); the universal-property data $(\iota_P,\, \text{factorisation})$ is then carried by the Albanese predicate (Definition~\ref{def:IsAlbanese}) and projects directly into the three results of this chapter (Layer~II): the Abel--Jacobi map $\alpha_P := \iota_P$ of Definition~\ref{def:ofCurve}, its pointed property of Lemma~\ref{lem:comp_ofCurve}, and the universal factorisation of Theorem~\ref{thm:exists_unique_ofCurve_comp}. Existence of a uniform-over-$P$ Albanese object is the single remaining mathematical hypothesis pending the formalisation of either Pic-scheme representability (Route~A), symmetric-power quotients plus Stein factorisation (Route~B), or rigidity for $C \to A$ established \emph{directly over $k$} (genus-$0$ sub-case, via \cref{thm:rigidity_over_kbar} per the iter-127 over-k commitment; no base-change to $\bar k$ and no Galois descent of morphism equality enter, and sub-step C.2.f of \S~C.2 is correspondingly DROPPED).
88	
89	The classical proof via line bundles --- using the universal property of $\Pic^0_{C/k}$, dual abelian varieties, and (for the genus-$0$ sub-case) rigidity for $C \to A$ established directly over $k$ via \cref{thm:rigidity_over_kbar} (per the iter-127 over-k commitment; no base-change to $\bar k$ and no Galois descent of morphism equality enter) --- gives the same conclusions but requires more Mathlib infrastructure than is presently available, as catalogued in the proof of Theorem~\ref{thm:nonempty_jacobianWitness} and the milestone roadmap of \texttt{STRATEGY.md}. The Albanese-framework route used here is mathematically equivalent and bundles all of the missing infrastructure into that single deferred existence hypothesis.
90

1	\chapter{Sheaf condition along the structure-sheaf forget composite}
2	\label{chap:Cohomology_SheafCompose}
3	
4	This chapter records the first step of Phase~A: equipping the abstract sheaf-cohomology pipeline with the link it needs to compute $H^1(C, \mathcal O_C)$ as an abelian group. It is the smallest unblocking unit of progress toward the genus of a smooth proper curve (Definition~\ref{def:genus}).
5	
6	The chapter introduces no protected declarations: every definition and lemma here is auxiliary, supporting the construction of $H^1(C, \mathcal O_C)$ in subsequent Phase~A iterations.
7	
8	\section{Statement}
9	
10	The structure sheaf $\mathcal O_C$ of a scheme is delivered as a sheaf of commutative rings. To plug it into the cohomology API, which is formulated for sheaves of abelian groups, one must first transport the sheaf condition along the forgetful composite $\mathrm{CommRing} \to \mathrm{Ring} \to \mathrm{Ab}$. The following theorem packages exactly this transport.
11	
12	\begin{theorem}\leanok
13	[Sheaf condition transports along the structure-sheaf forget composite]
14	  \label{thm:HasSheafCompose_forget}
15	  \lean{AlgebraicGeometry.Cohomology.instHasSheafCompose_forget_CommRing_AddCommGrp}
16	  Let $X$ be a topological space. Then the Grothendieck topology of opens of $X$ transports sheaves along the forgetful composite from commutative rings to abelian groups.
17	\end{theorem}
18	
19	\begin{proof}
20	
21	
22	\leanok
23	  Both forgetful functors in the composite $\mathrm{CommRing} \to \mathrm{Ring} \to \mathrm{Ab}$ create (in particular preserve) all small limits. The sheaf condition for the topology of opens is expressed as preservation of certain multiequalizer limits. Composing two limit-preserving functors gives a limit-preserving functor, so post-composition with the forget composite preserves the sheaf condition.
24	\end{proof}
25	
26	\section{Use in the project}
27	
28	Theorem~\ref{thm:HasSheafCompose_forget} is the gateway to:
29	\begin{itemize}
30	  \item constructing $\mathcal O_C$ as a sheaf of abelian groups on $C$;
31	  \item plugging that sheaf into the abstract cohomology functor once sheafification and $\Ext$ are available (Phase~A steps 2--3);
32	  \item endowing the resulting $H^1$ with a $k$-vector-space structure via the $k$-algebra structure on $\Gamma(C, \mathcal O_C)$ (Phase~A step~4);
33	  \item finite-dimensionality via Serre's theorem on coherent cohomology of proper $k$-schemes (Phase~A step~5).
34	\end{itemize}
35	
36	The chain is: sheaf-compose transport (this chapter) $\to$ sheafification $\to$ $\Ext$ $\to$ $k$-module structure on $H^1$ $\to$ Serre finiteness $\to$ genus.
37	
38	\begin{remark}[Lean implementation]
39	  In Lean the forget composite is written as the concatenation of the two structure-forgetful functors $\mathrm{CommRingCat} \to \mathrm{RingCat} \to \mathrm{AddCommGrpCat}$. The proof appeals to the general fact that a functor preserving limits of a given size preserves the sheaf condition when post-composed with a presheaf. The instance body is a 5-line composition of Mathlib's limit-preservation lemmas.
40	\end{remark}
41

